1	const BASE_PREMIUMS: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	  rune: 25,
7	};
8	
9	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
10	const PROCESSING_FEE = 5;
11	const COMPONENT_TYPES = new Set(["rune"]);
12	const COMPONENT_BLOCK_SIZE = 3;
13	const COMPONENT_BLOCK_BASE = 60;
14	
15	const baseForType = (type: string, count: number): number => {
16	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
17	    return COMPONENT_BLOCK_BASE;
18	  }
19	  return count * BASE_PREMIUMS[type];
20	};
21	
22	export const runScenario = (scenario: any): unknown => {
23	  const items = scenario.steps[0].items;
24	  const countsByType = new Map<string, number>();
25	  for (const item of items) {
26	    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
27	  }
28	  let itemsBase = 0;
29	  for (const [type, count] of countsByType) {
30	    itemsBase += baseForType(type, count);
31	  }
32	  const itemsTotal = itemsBase + itemsBase * FIRST_INSURANCE_SURCHARGE_RATE;
33	  const premium = Math.ceil(itemsTotal + PROCESSING_FEE);
34	  return { results: [{ premium }] };
35	};
